const body = items[0].json.body || items[0].json;

const email = (body.email || '').toLowerCase().trim();
const couponCode = (body.coupon_code || '').trim();

// Generate token code BGT-XXXX-XXXX
const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
let tokenCode = 'BGT-';
for (let i = 0; i < 4; i++) tokenCode += chars[Math.floor(Math.random() * chars.length)];
tokenCode += '-';
for (let i = 0; i < 4; i++) tokenCode += chars[Math.floor(Math.random() * chars.length)];

return [{
  json: {
    email,
    coupon_code: couponCode,
    token_code: tokenCode
  }
}];

const coupon = items[0].json;
const purchaseData = $node['Parse Body & Generate Code'].json;
let discountPercent = 0;
let couponId = null;

if (coupon && coupon.id) {
  // Validate coupon
  if (coupon.max_uses && coupon.times_used >= coupon.max_uses) {
    discountPercent = 0;
  } else if (coupon.expires_at && new Date(coupon.expires_at) < new Date()) {
    discountPercent = 0;
  } else {
    discountPercent = coupon.discount_percent || 0;
    couponId = coupon.id;
  }
}

return [{
  json: {
    email: purchaseData.email,
    token_code: purchaseData.token_code,
    coupon_id: couponId,
    discount_percent: discountPercent
  }
}];

// No coupon path — pass through with 0 discount
const purchaseData = $node['Parse Body & Generate Code'].json;

return [{
  json: {
    email: purchaseData.email,
    token_code: purchaseData.token_code,
    coupon_id: null,
    discount_percent: 0
  }
}];

const pricing = items[0].json;
const prevData = $node['Validate Coupon'].json || $node['No Coupon'].json;

// Merge: take whichever path had data
const email = prevData.email;
const tokenCode = prevData.token_code;
const couponId = prevData.coupon_id;
const discountPercent = prevData.discount_percent || 0;

const basePriceCents = pricing.price_cents || 9900; // fallback R99.00
const discountAmount = Math.round(basePriceCents * discountPercent / 100);
const finalPriceCents = basePriceCents - discountAmount;
const isFree = finalPriceCents <= 0;

return [{
  json: {
    email,
    token_code: tokenCode,
    coupon_id: couponId,
    discount_percent: discountPercent,
    base_price_cents: basePriceCents,
    final_price_cents: isFree ? 0 : finalPriceCents,
    is_free: isFree
  }
}];

const data = items[0].json;
const amountRands = (data.final_price_cents / 100).toFixed(2);

const fields = {
  merchant_id: '10000100',
  merchant_key: '46f0cd694581a',
  return_url: 'https://beegraded.co.za/thank-you?token_code=' + data.token_code,
  cancel_url: 'https://beegraded.co.za/cancel',
  notify_url: 'https://beegraded.co.za/webhook/bg-token-itn',
  email_address: data.email,
  amount: amountRands,
  item_name: 'BeeGraded Evaluation Token',
  item_description: 'Token code: ' + data.token_code,
  custom_str1: data.token_code,
  custom_str2: data.email
};

// Insert pending token
return [{
  json: {
    ...data,
    payfast_fields: fields,
    payfast_url: 'https://sandbox.payfast.co.za/eng/process',
    amount_rands: amountRands
  }
}];
